/**
 * HunkSummaryRenderer - Renders inline natural-language hunk summaries.
 *
 * A summary is a short natural-language description of a non-trivial hunk,
 * generated by a background AI job. This renderer supports two rendering
 * backends that share one annotation card body:
 *
 *   - Legacy table (`renderInline`): inserts a `<tr class="hunk-summary-row">`
 *     immediately ABOVE the hunk's first code row. Used when @pierre/diffs is
 *     unavailable and the file rendered through the legacy `renderPatch` path.
 *
 *   - @pierre/diffs (`renderPierre`): registers a line annotation with
 *     PierreBridge so the same card slots into the light DOM BELOW the hunk's
 *     first line. The card carries the `hunk-summary-row` class as a `<div>`
 *     so the identical page CSS (styling + visibility toggles) applies.
 *
 * Visibility is controlled outside the renderer via CSS classes:
 *   - body.summaries-hidden                    — review-level toggle
 *   - .d2h-file-wrapper.summaries-hidden-file  — per-file toggle
 *
 * Trivial / model-skipped / model-malformed rows are filtered out by the
 * caller; this renderer only handles rows with non-empty `summary_text`.
 */

class HunkSummaryRenderer {
  /**
   * @param {Object} prManager - PRManager instance (used to reach PierreBridge).
   */
  constructor(prManager) {
    this.prManager = prManager;
    // Map<contentHash, HTMLTableRowElement> — legacy annotation rows mounted
    this._mounted = new Map();
    // Map<contentHash, {fileName, id}> — Pierre annotations mounted via the
    // bridge. Kept separate from `_mounted` because Pierre summaries live in
    // PierreBridge's annotation list (not a DOM row we own).
    this._pierreMounted = new Map();
    // Guards one-time registration of the 'hunk-summary' annotation renderer
    // with PierreBridge (the bridge is created after this renderer, so we
    // register lazily on first Pierre mount).
    this._bridgeRendererRegistered = false;
  }

  /**
   * Deterministic PierreBridge annotation id for a summary. Deterministic so a
   * re-mount can target (remove/replace) the existing annotation by id.
   * @param {string} contentHash
   * @returns {string}
   */
  static pierreAnnotationId(contentHash) {
    return `hunk-summary-${contentHash}`;
  }

  /**
   * Build the inner annotation card (`.hunk-summary-annotation`) shared by the
   * legacy `<tr>` and the Pierre `<div>` wrappers. Contains the icon + text.
   * @param {Object} summary - { summary_text }
   * @returns {HTMLDivElement}
   * @private
   */
  _buildAnnotationEl(summary) {
    const annotation = document.createElement('div');
    annotation.className = 'hunk-summary-annotation';

    const icon = document.createElement('span');
    icon.className = 'hunk-summary-icon';
    icon.setAttribute('aria-hidden', 'true');
    icon.innerHTML = '<svg viewBox="0 0 16 16" width="14" height="14" fill="currentColor">' +
      '<path d="M0 3.75C0 2.784.784 2 1.75 2h12.5c.966 0 1.75.784 1.75 1.75v8.5A1.75 1.75 0 0 1 14.25 14H1.75A1.75 1.75 0 0 1 0 12.25Zm1.75-.25a.25.25 0 0 0-.25.25v8.5c0 .138.112.25.25.25h12.5a.25.25 0 0 0 .25-.25v-8.5a.25.25 0 0 0-.25-.25ZM3.5 6.25a.75.75 0 0 1 .75-.75h7a.75.75 0 0 1 0 1.5h-7a.75.75 0 0 1-.75-.75Zm.75 2.25h4a.75.75 0 0 1 0 1.5h-4a.75.75 0 0 1 0-1.5Z"/>' +
      '</svg>';

    const text = document.createElement('span');
    text.className = 'hunk-summary-text';
    text.textContent = summary.summary_text;

    annotation.appendChild(icon);
    annotation.appendChild(text);
    return annotation;
  }

  /**
   * Render a summary inline, immediately above its hunk anchor row.
   * Idempotent: if a summary for the same hash is already mounted, replace
   * its text rather than stack a duplicate.
   *
   * @param {HTMLTableRowElement} anchorRow - The first code-line `<tr>` of
   *   the target hunk (carries `data-hunk-start="${contentHash}"`).
   * @param {Object} summary - Summary object: { content_hash, summary_text }.
   * @param {Object} [_opts] - Reserved for future per-render options.
   * @returns {HTMLTableRowElement|null}
   */
  renderInline(anchorRow, summary, _opts) {
    if (!anchorRow || !summary || !summary.summary_text) return null;
    const contentHash = summary.content_hash;
    if (!contentHash) return null;

    const existing = this._mounted.get(contentHash);
    if (existing && existing.isConnected) {
      const textEl = existing.querySelector('.hunk-summary-text');
      if (textEl) textEl.textContent = summary.summary_text;
      return existing;
    }

    const row = document.createElement('tr');
    row.className = 'hunk-summary-row';
    row.dataset.contentHash = contentHash;

    const cell = document.createElement('td');
    cell.colSpan = 2;
    cell.className = 'hunk-summary-cell';

    cell.appendChild(this._buildAnnotationEl(summary));
    row.appendChild(cell);

    // Insert IMMEDIATELY ABOVE the hunk's first code line so a reader
    // scrolling down sees the description before the change itself.
    anchorRow.parentNode.insertBefore(row, anchorRow);
    this._mounted.set(contentHash, row);
    return row;
  }

  /**
   * Build the Pierre annotation card wrapper. A `<div class="hunk-summary-row">`
   * so the SAME page CSS that styles/hides the legacy `<tr class="hunk-summary-row">`
   * applies to the slotted light-DOM element. Registered with PierreBridge as
   * the 'hunk-summary' renderer.
   * @param {Object} summary - { content_hash, summary_text }
   * @returns {HTMLDivElement|null}
   * @private
   */
  _buildPierreCard(summary) {
    if (!summary || !summary.summary_text) return null;
    const card = document.createElement('div');
    card.className = 'hunk-summary-row';
    if (summary.content_hash) card.dataset.contentHash = summary.content_hash;
    card.appendChild(this._buildAnnotationEl(summary));
    return card;
  }

  /**
   * Register the 'hunk-summary' annotation renderer with PierreBridge once.
   * The bridge invokes the callback with the summary data whenever it (re)slots
   * a hunk-summary annotation — including after worker rebuilds / content
   * upgrades, which re-apply `fileState.annotations`.
   * @param {Object} bridge - PierreBridge instance
   * @private
   */
  _ensureBridgeRenderer(bridge) {
    if (this._bridgeRendererRegistered || !bridge?.registerAnnotationRenderer) return;
    bridge.registerAnnotationRenderer('hunk-summary', (data) => this._buildPierreCard(data));
    this._bridgeRendererRegistered = true;
  }

  /**
   * Mount (or update in place) a summary against a Pierre-rendered file via a
   * line annotation. Idempotent: re-mounting the same hash removes the prior
   * annotation first so the card's text refreshes without stacking duplicates.
   *
   * @param {string} fileName - File the annotation belongs to
   * @param {{lineNumber: number, side: string}} anchor - Anchor position
   * @param {Object} summary - { content_hash, summary_text }
   * @returns {string|null} The annotation id if mounted, else null
   */
  renderPierre(fileName, anchor, summary) {
    const bridge = this.prManager?.pierreBridge;
    if (!bridge || !fileName || !anchor) return null;
    if (!summary || !summary.summary_text) return null;
    const contentHash = summary.content_hash;
    if (!contentHash) return null;

    this._ensureBridgeRenderer(bridge);

    const id = HunkSummaryRenderer.pierreAnnotationId(contentHash);
    // Idempotent update: drop any existing annotation for this hash before
    // re-adding so the text refreshes in place (the bridge appends by id).
    if (this._pierreMounted.has(contentHash)) {
      bridge.removeAnnotation(fileName, id);
    }
    bridge.addAnnotation(fileName, {
      lineNumber: anchor.lineNumber,
      side: anchor.side,
      type: 'hunk-summary',
      id,
      data: summary,
    });
    this._pierreMounted.set(contentHash, { fileName, id });
    return id;
  }

  /**
   * Remove a mounted annotation by its content hash, from whichever backend
   * (legacy `<tr>` or Pierre annotation) it was mounted through.
   * @param {string} contentHash
   * @returns {boolean} true if an annotation was found and removed
   */
  removeByHash(contentHash) {
    let removed = false;
    const row = this._mounted.get(contentHash);
    if (row) {
      if (row.isConnected) row.remove();
      this._mounted.delete(contentHash);
      removed = true;
    }
    const pierre = this._pierreMounted.get(contentHash);
    if (pierre) {
      this.prManager?.pierreBridge?.removeAnnotation(pierre.fileName, pierre.id);
      this._pierreMounted.delete(contentHash);
      removed = true;
    }
    return removed;
  }

  /**
   * Clear all mounted annotations (e.g. before re-rendering the diff).
   *
   * Pierre annotations are dropped from the bridge too. In practice PRManager
   * calls `pierreBridge.destroyAll()` before this during renderDiff, so those
   * removes are no-ops on already-destroyed files — but doing it here keeps the
   * renderer correct if reset() is ever called on its own.
   */
  reset() {
    for (const row of this._mounted.values()) {
      if (row.isConnected) row.remove();
    }
    this._mounted.clear();
    const bridge = this.prManager?.pierreBridge;
    if (bridge) {
      for (const { fileName, id } of this._pierreMounted.values()) {
        bridge.removeAnnotation(fileName, id);
      }
    }
    this._pierreMounted.clear();
  }
}

if (typeof window !== 'undefined') {
  window.HunkSummaryRenderer = HunkSummaryRenderer;
}

if (typeof module !== 'undefined' && module.exports) {
  module.exports = { HunkSummaryRenderer };
}
